<template>
	<view class="container">
		<div class="box2">
			<!-- 标题 -->
			<Mtitle title="contacts"></Mtitle>

			<!-- 联系人列表 -->
			<view class="box">
				<view class="scrollContent">
					<scroll-view scroll-y="true" class="scrollView">
						<!-- 使用 v-for 动态渲染 -->
						<customer v-for="contact in contacts" :key="contact.uid" :customer="contact.username"
							:content="contact.bio || '暂无签名'" :avatar="contact.avatar_url" :company="contact.company">
						</customer>
					</scroll-view>
				</view>
			</view>

			<!-- 导航按钮 -->
			<navigator url="/pages/orderDetails/orderDetails"></navigator>

			<!-- 底部按钮组 -->
			<view class="buttonLump">
				<newBar title="new" to="/pages/orders/orders"></newBar>
				<newBar title="post" to="/pages/orderDetails/orderDetails"></newBar>
			</view>
		</div>
	</view>
</template>

<!-- src/pages/contacts/contacts.vue -->
<script setup>
	import {
		onMounted,
		ref
	} from 'vue'

	// 1. 定义联系人列表
	const contacts = ref([])

	// 2. 获取联系人数据
	const getContacts = async () => {
		try {
			const token = uni.getStorageSync('token') // uni-app 获取本地存储

			if (!token) {
				uni.showToast({
					title: '请先登录',
					icon: 'none'
				})
				return
			}

			// 发起请求
			const res = await uni.request({
				url: 'http://localhost:5000/api/contacts/contacts',
				method: 'GET',
				header: {
					'Authorization': `Bearer ${token}`,
					'Content-Type': 'application/json'
				}
			})

			// 成功响应
			if (res.statusCode === 200) {
				console.log('获取到的联系人数据:', res.data.data);
				contacts.value = res.data.data // 把返回的联系人列表赋值
			} else {
				uni.showToast({
					title: '获取失败',
					icon: 'none'
				})
			}
		} catch (error) {
			console.error('获取联系人失败:', error)
			uni.showToast({
				title: '网络错误',
				icon: 'none'
			})
		}
	}

	// 3. 页面加载时获取数据
	onMounted(() => {
		getContacts()
	})
</script>

